app = Flask(__name__)
app.secret_key = os.urandom(24) # Replace with a strong, permanent secret key in production

# Helper function to get Flask request parameters into a format python3-saml expects
def prepare_flask_request(request):
    url_data = OneLogin_Saml2_Utils.get_base_url(request.url)
    return {
        'http_host': request.host,
        'server_port': request.port,
        'script_name': request.path,
        'get_data': request.args.copy(),
        'post_data': request.form.copy(),
        'query_string': request.query_string.decode('utf-8'),
        'base_url': url_data,
        'https': 'on' if request.scheme == 'https' else 'off'
    }

@app.route('/')
def index():
    if 'samlUserdata' in session:
        return render_template('index.html', logged_in=True, user_data=session['samlUserdata'])
    return render_template('index.html', logged_in=False)

@app.route('/saml/login')
def saml_login():
    """
    Initiates the SAML SSO process by sending an AuthNRequest to the IdP.
    """
    req = prepare_flask_request(request)
    auth = OneLogin_Saml2_Auth(req, SAML_SETTINGS)
    return redirect(auth.login())

@app.route('/saml/acs', methods=['POST'])
def saml_acs():
    """
    Receives the SAML Response from the IdP and processes it.
    This is the Assertion Consumer Service (ACS) endpoint.
    """
    req = prepare_flask_request(request)
    auth = OneLogin_Saml2_Auth(req, SAML_SETTINGS)

    # Process the SAML Response
    auth.process_response()

    # Check for SAML errors
    if auth.get_errors():
        error_reason = auth.get_last_error_reason()
        flash(f'SAML Error: {error_reason}', 'danger')
        app.logger.error(f"SAML Error: {auth.get_last_error_reason()}")
        app.logger.error(f"SAML Error Details: {auth.get_errors()}")
        return redirect(url_for('index'))

    # Check if the user is authenticated (i.e., SAML response is valid and signature checks passed)
    if not auth.is_authenticated():
        flash('Not authenticated through SAML. Invalid SAML Response.', 'danger')
        app.logger.error("SAML authentication failed: is_authenticated() returned false.")
        return redirect(url_for('index'))

    # Authentication successful, extract user data
    session['samlUserdata'] = auth.get_attributes()
    session['samlNameId'] = auth.get_nameid()
    session['samlNameIdFormat'] = auth.get_nameid_format()
    session['samlSessionIndex'] = auth.get_session_index()

    # Log extracted assertions for verification
    app.logger.info(f"SAML User NameID: {session['samlNameId']}")
    app.logger.info(f"SAML User Attributes: {session['samlUserdata']}")
    app.logger.info(f"SAML Session Index: {session['samlSessionIndex']}")

    flash('Successfully logged in via SAML!', 'success')

    # Redirect to a dashboard or protected page
    return redirect(url_for('dashboard'))

@app.route('/saml/sls')
def saml_sls():
    """
    Receives the SAML Logout Response from the IdP.
    This is the Single Logout Service (SLS) endpoint.
    """
    req = prepare_flask_request(request)
    auth = OneLogin_Saml2_Auth(req, SAML_SETTINGS)

    # Process the SAML Logout Response
    auth.process_slo()

    errors = auth.get_errors()
    if not errors:
        session.clear() # Clear Flask session on successful logout
        flash('You have been logged out via SAML.', 'info')
    else:
        flash(f'Error during SAML logout: {auth.get_last_error_reason()}', 'danger')
        app.logger.error(f"SAML SLO Error: {auth.get_last_error_reason()}")
        app.logger.error(f"SAML SLO Error Details: {errors}")

    return redirect(url_for('index'))

@app.route('/logout')
def logout():
    """
    Initiates SP-initiated Single Logout.
    """
    if 'samlUserdata' in session:
        req = prepare_flask_request(request)
        auth = OneLogin_Saml2_Auth(req, SAML_SETTINGS)

        # Prepare logout request with NameID and SessionIndex
        name_id = session.get('samlNameId')
        name_id_format = session.get('samlNameIdFormat')
        session_index = session.get('samlSessionIndex')

        # Clear local session first
        session.clear()

        # Redirect to IdP for SLO
        return redirect(auth.logout(
            name_id=name_id,
            session_index=session_index,
            name_id_format=name_id_format
        ))
    else:
        flash('You were not logged in.', 'warning')
        return redirect(url_for('index'))

@app.route('/dashboard')
def dashboard():
    """
    A protected page that requires SAML authentication.
    """
    if 'samlUserdata' not in session:
        flash('You must log in to access the dashboard.', 'warning')
        return redirect(url_for('index'))

    user_data = session['samlUserdata']
    # Example: Accessing a specific attribute like 'Email' or 'Username'
    email = user_data.get('Email', ['N/A'])[0] # Assuming 'Email' attribute exists
    username = user_data.get('username', ['N/A'])[0] # Example for Keycloak's 'username'

    return render_template('dashboard.html', user_data=user_data, email=email, username=username)

